mapper.select:
SELECT t.*, o.order_number AS stockInOrderNumber, w.warehouse_name AS warehouseName, c.owner_name AS ownerName, p.product_name AS productName, p.owner_id AS ownerId FROM wms_tasks t LEFT JOIN wms_stock_in_orders o ON t.stock_in_order_id = o.id LEFT JOIN wms_warehouses w ON t.target_warehouse_id = w.id LEFT JOIN wms_products p ON t.product_id = p.id LEFT JOIN wms_cargo_owners c ON p.owner_id = c.id
AND t.task_type = #{taskType}
AND t.task_number LIKE CONCAT('%', #{taskNumber}, '%')
AND t.task_status = #{taskStatus}
AND t.operator = #{operator}
AND o.order_number LIKE CONCAT('%', #{stockInOrderNumber}, '%')
ORDER BY t.create_time DESC
